    pub async fn execute_async(
        self,
    ) -> Result<crate::proto::tempo_world::SetPropertiesResponse, crate::TempoError> {
        let channel = crate::context::connected_channel().await?;
        let mut client = crate::proto::tempo_world::world_control_service_client::WorldControlServiceClient::new(channel)
            .max_decoding_message_size(crate::context::MAX_MESSAGE_SIZE)
            .max_encoding_message_size(crate::context::MAX_MESSAGE_SIZE);

        let request = crate::proto::tempo_world::SetPropertiesRequest { ops: self.ops };
        let response = client.set_properties(request).await?;
        Ok(response.into_inner())
    }

    pub fn execute(
        self,
    ) -> Result<crate::proto::tempo_world::SetPropertiesResponse, crate::TempoError> {
        crate::context::RUNTIME.block_on(self.execute_async())
    }
